const express = require('express');
const multer = require('multer');
const xml2js = require('xml2js');

const app = express();
const upload = multer({
  storage: multer.memoryStorage(),
  limits: {
    fileSize: 2 * 1024 * 1024
  }
});

function extractValue(node) {
  if (node == null) return null;
  if (typeof node !== 'object') return node;
  if (Array.isArray(node)) {
    if (node.length === 1) return extractValue(node[0]);
    return node.map(extractValue);
  }
  if ('_' in node && Object.keys(node).length === 1) return node._;
  const result = {};
  for (const [key, value] of Object.entries(node)) {
    if (key === '$') {
      result.attributes = value;
    } else {
      result[key] = extractValue(value);
    }
  }
  return result;
}

function extractConfiguration(parsedXml) {
  const rootKey = Object.keys(parsedXml)[0];
  const root = parsedXml[rootKey];
  return {
    rootElement: rootKey,
    configuration: extractValue(root)
  };
}

app.post('/upload-xml', upload.single('file'), async (req, res) => {
  try {
    if (!req.file || !req.file.buffer) {
      return res.status(400).json({ error: 'No XML file uploaded' });
    }

    const xmlContent = req.file.buffer.toString('utf8');

    const parser = new xml2js.Parser({
      explicitArray: false,
      trim: true,
      normalize: true,
      xmlns: false,
      explicitCharkey: false
    });

    const parsedXml = await parser.parseStringPromise(xmlContent);
    const result = extractConfiguration(parsedXml);

    res.json({
      success: true,
      settings: result
    });
  } catch (error) {
    res.status(400).json({
      success: false,
      error: 'Invalid XML document',
      details: error.message
    });
  }
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});